/**
 * 提现主页面
 */

import { useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { useCashout } from "@/hooks/useCashout";
import { useUser } from "@/hooks/useUser";
import { cashoutStagesList, PaymentMethod } from "@/types/cashout";
import { getStageIndex } from "@/utils/cashoutUtils";
import NavigationBar from "@/components/NavigationBar";
import { bpTrack } from "@/tracking";
import { EventName } from "@/tracking/events";
import cashoutPaypal from "@/assets/images/cash_v2/cashout_paypal.webp";
import cashoutVisa from "@/assets/images/cash_v2/cashout_visa.webp";
import cashoutAmazon from "@/assets/images/cash_v2/cashout_amazon.webp";
import cashoutBank from "@/assets/images/cash_v2/cashout_bank.webp";
import { PaymentMethodCard } from "./PaymentMethodCard";
import { StageTaskContainer } from "./StageTaskContainer";

// 支付方式配置
const paymentMethodConfig = [
  { method: PaymentMethod.PayPal, image: cashoutPaypal, name: "PayPal" },
  { method: PaymentMethod.Visa, image: cashoutVisa, name: "Virtual Visa" },
  { method: PaymentMethod.Amazon, image: cashoutAmazon, name: "Amazon.com" },
  { method: PaymentMethod.Bank, image: cashoutBank, name: "Bank" },
];

export default function CashoutPage() {
  const navigate = useNavigate();
  const { cash, fetchPaypalAccount } = useUser();
  const { currentTaskStage, willCashoutStage, withdrawList, fetchWithdrawList } = useCashout();

  useEffect(() => {
    fetchWithdrawList();
    fetchPaypalAccount(); // 获取 PayPal 账号

    // 埋点：提现页面展示
    bpTrack(EventName.pwa_cashout_click);
    bpTrack(EventName.pwa_checkout_unlocked_page_show);
  }, [fetchWithdrawList, fetchPaypalAccount]);

  const onRecordClick = () => {
    navigate("/cashout/record");
  };

  const recordButton = withdrawList && withdrawList.length > 0 && (
    <button
      onClick={onRecordClick}
      className="px-4 py-2 text-black text-sm bg-[#6BC4FF] border-none rounded-[28px] cursor-pointer font-[Pangram]"
    >
      Record
    </button>
  );

  return (
    <div className="flex flex-col min-h-full bg-surface animate-fade-in">
      {/* 顶部区域 */}
      <div className="flex flex-col bg-gradient-to-b from-brand to-[rgba(71,174,239,0)]">
        <NavigationBar title="Cashout" sticky={false} rightSlot={recordButton} />

        {/* 余额显示 */}
        <div className="mt-6 ml-4 text-[#020202] font-medium text-xs leading-normal font-[Pangram] capitalize">
          Balance:
        </div>
        <div className="mt-[15px] ml-4 font-extrabold text-[40px] leading-normal font-[TTFellows]">
          {`$${cash.toFixed(2)}`}
        </div>
      </div>

      {/* 支付方式 */}
      <div className="mt-8 ml-4 text-black font-medium text-[15px] leading-normal font-[Pangram] capitalize">
        Most Popular
      </div>
      <div className="grid grid-cols-2 gap-x-[10px] gap-y-4 mx-4 mt-4">
        {paymentMethodConfig.map((item) => (
          <PaymentMethodCard key={item.method} item={item} />
        ))}
      </div>

      {/* Cash Out 标题 */}
      <div className="mt-8 ml-4 text-black font-extrabold text-[22px] leading-normal font-[Pangram] capitalize">
        Cash Out
      </div>

      {/* 阶段任务列表 */}
      {cashoutStagesList.map((stage, index) => {
        const willCashoutStageIndex = getStageIndex(willCashoutStage);
        const currentTaskStageIndex = getStageIndex(currentTaskStage);
        const shouldRender = index >= willCashoutStageIndex || index === currentTaskStageIndex;

        if (!shouldRender) return null;

        return <StageTaskContainer key={stage} stage={stage} />;
      })}
    </div>
  );
}
